type EventMap = Record<string, any>;
type EventHandler<T> = (data: T) => void;

export class TypedEventEmitter<Events extends EventMap> {
  private handlers: {
    [K in keyof Events]?: EventHandler<Events[K]>[];
  } = {};

  on<K extends keyof Events>(event: K, handler: EventHandler<Events[K]>): () => void {
    if (!this.handlers[event]) {
      this.handlers[event] = [];
    }
    this.handlers[event]!.push(handler);
    return () => this.off(event, handler);
  }

  off<K extends keyof Events>(event: K, handler: EventHandler<Events[K]>): void {
    const list = this.handlers[event];
    if (list) {
      this.handlers[event] = list.filter((h) => h !== handler) as any;
    }
  }

  protected emit<K extends keyof Events>(event: K, data: Events[K]): void {
    const list = this.handlers[event];
    if (list) {
      for (const handler of list) {
        handler(data);
      }
    }
  }
}

import { TypedEventEmitter } from './event-emitter';

interface StoreEvents<T> {
  change: { prev: T; next: T };
  reset: T;
}

export class Store<T> extends TypedEventEmitter<StoreEvents<T>> {
  private value: T;
  private initialValue: T;

  constructor(initialValue: T) {
    super();
    this.value = initialValue;
    this.initialValue = initialValue;
  }

  get(): T {
    return this.value;
  }

  set(newValue: T): void {
    const prev = this.value;
    this.value = newValue;
    this.emit('change', { prev, next: newValue });
  }

  reset(): void {
    this.value = this.initialValue;
    this.emit('reset', this.initialValue);
  }

  subscribe(listener: (value: T) => void): () => void {
    return this.on('change', ({ next }) => listener(next));
  }
}
